+import { describe, expect, it } from "vitest"
+
+import { hasFiltersChanged } from "../checkFilters"
+
+describe("hasFiltersChanged", () => {
+  it("returns false when current and initial filters are identical", () => {
+    const filter = { listingPriceFrom: 10000, listingPriceTo: 50000 }
+    expect(hasFiltersChanged(filter, filter)).toBe(false)
+  })
+
+  it("returns true when a value changes", () => {
+    const initial = { listingPriceFrom: 10000 }
+    const current = { listingPriceFrom: 20000 }
+    expect(hasFiltersChanged(current, initial)).toBe(true)
+  })
+
+  it("returns true when a new key is added", () => {
+    const initial = { listingPriceFrom: 10000 }
+    const current = { listingPriceFrom: 10000, listingPriceTo: 50000 }
+    expect(hasFiltersChanged(current, initial)).toBe(true)
+  })
+
+  it("ignores false boolean entries — unchecked checkboxes are not substantive changes", () => {
+    const initial = {}
+    const current = { draft: false, featured: false }
+    expect(hasFiltersChanged(current, initial)).toBe(false)
+  })
+
+  it("ignores empty object entries — cleared checkbox groups are not substantive changes", () => {
+    const initial = {}
+    const current = { status: {} }
+    expect(hasFiltersChanged(current, initial)).toBe(false)
+  })
+
+  it("ignores false booleans nested inside a filter group", () => {
+    const initial = { status: { listed: true } }
+    const current = { status: { listed: true, draft: false } }
+    expect(hasFiltersChanged(current, initial)).toBe(false)
+  })
+
+  it("returns true when a true boolean entry is added", () => {
+    const initial = {}
+    const current = { featured: true }
+    expect(hasFiltersChanged(current, initial)).toBe(true)
+  })
+
+  it("returns false when both sides have only false booleans and empty objects", () => {
+    const initial = { draft: false, status: {} }
+    const current = { featured: false, niche: {} }
+    expect(hasFiltersChanged(current, initial)).toBe(false)
+  })
+
+  it("handles undefined/null values without throwing", () => {
+    expect(hasFiltersChanged(undefined, undefined)).toBe(false)
+    expect(hasFiltersChanged(null, null)).toBe(false)
+    expect(hasFiltersChanged(undefined, null)).toBe(false)
+  })
+})
